        'officer_geologist_description' => 'Geolog je strucnjak u astrominerologiji i kristalografiji. On pomaze svojim timovima u metalurgiji i kemijii, te ujedno brine o meduplanetarnim komunikacijama poboljšavajući korištenje i prerađivanje sirovina uzduž čitavog imperija. Koristeci vrhunsku opremu za prezivljavanje, Geolog moze pronaci optimalna mjesta za rudarenje te tako povecati produkciju rudnika za 10%.',
        'officer_geologist_benefits' => '+10% proizvodnje metala, kristala i deuterijuma na svim planetama.',
        'officer_geologist_benefit_mines' => '+10% proizvodnja rudnika',
        'officer_geologist_tooltip' => '<b>+10% proizvodnja rudnika</b><p>Vaši rudnici proizvode 10% više.</p>',
        'officer_technocrat_title' => 'Tehnocrat',
        'officer_technocrat_description' => 'Skup Technocrata sastavljen je od genijalnih znanstvenika, pronaci ih mozes stalno preko granice imperije gdje se sve prkosi ljudskoj logici. U tisucu godina nitko od normalnih ljudi nije nikad probio sifru Technocrata. Technocrat inspirira istrazivace imperije svojim prisustvom.',
        'officer_technocrat_benefits' => '-25% vremena istraživanja za sve tehnologije.',
        'officer_technocrat_benefit_espionage' => '+2 nivo špijunaže',
        'officer_technocrat_benefit_research' => '25% manje vremena istraživanja',
        'officer_technocrat_tooltip' => '<b>+2 nivo špijunaže</b><p>2 nivoi će biti dodani vašem istraživanju špijunaže.</p><br/><b>25% manje vremena istraživanja</b><p>Vašem istraživanju treba 25% manje vremena do završetka.</p>',
        'officer_all_officers_title' => 'Zapovjedno osoblje',
